/// <summary>
/// Class for action menu item SalesConfirmReportPortuguese
/// Calls report controller for SSRS report ETGSalesConfirm - ETGSalesOrderReportPL
/// </summary>
internal final class ETGSalesConfirmReportPortuguese
{
}

Method.Source:
/// <summary>
/// Class entry point. The system will call this method when a designated menu 
/// is selected or when execution starts and this class is set as the startup class.
/// </summary>
/// <param name = "_args">The specified arguments.</param>
public static void main(Args _args)
{
    CustConfirmJour     CustConfirmJour;
    SrsReportRunController reportRunController;
    SrsReportRunImpl        srsReportRun;
    SalesConfirmContract dataContract;

    if(_args.record() && _args.dataset() == tableNum(CustConfirmJour))
    {
        CustConfirmJour = _args.record();
    }
    else
    {
        throw Error(Error::missingFormActiveBuffer(formStr(CustConfirmJournal)));
    }
    reportRunController = new SrsReportRunController();
    dataContract = new  SalesConfirmContract();
    reportRunController.parmReportName(ssrsReportStr(ETGSalesConfirm,  ETGSalesOrderReportPL));
    reportRunController.parmShowDialog(false);
    dataContract = reportRunController.parmReportContract().parmRdpContract() as SalesConfirmContract;
    dataContract.parmRecordId(CustConfirmJour.RecId);
    srsReportRun = reportRunController.parmReportRun() as SrsReportRunImpl;
    reportRunController.parmShowDialog(false);
    reportRunController.parmReportRun(srsReportRun);
    reportRunController.parmDialogCaption('confirmation report - Portuguese');
    reportRunController.parmReportContract().parmPrintSettings().printMediumType(SRSPrintMediumType::Screen);
    reportRunController.startOperation();

}
